function saveDraft() {
  // Save current form state.
}

$("form").on("input", saveDraft);
$("form").off("input", saveDraft);

$.ajax({
  url: "/api/profile",
  method: "GET",
  dataType: "json"
}).done(function (profile) {
  $(".name").text(profile.name);
}).fail(function () {
  $(".error").text("Could not load profile");
});

